@app.route("/documents/aggregate/author-performance", methods=["GET"])
def aggregate_author_performance():
    pipeline = [
        {
            "$group": {
                "_id": "$author_id",
                "total_docs": {"$sum": 1},
                "published_docs": {
                    "$sum": {"$cond": [{"$eq": ["$status", "published"]}, 1, 0]}
                },
                "draft_docs": {
                    "$sum": {"$cond": [{"$eq": ["$status", "draft"]}, 1, 0]}
                },
            }
        },
        {
            "$addFields": {
                "publish_rate": {
                    "$cond": [
                        {"$eq": ["$total_docs", 0]},
                        0,
                        {"$divide": ["$published_docs", "$total_docs"]},
                    ]
                }
            }
        },
        {"$sort": {"published_docs": -1, "total_docs": -1}},
    ]
    results = list(documents.aggregate(pipeline))
    return jsonify({"results": results}), 200


